import { useState, useEffect, useRef } from 'react';
import { apiCall } from '../services/api';

const C = {
    overlay: { position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.55)', zIndex: 9999, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 20 },
    modal: { background: '#fff', borderRadius: 20, width: '100%', maxWidth: 420, boxShadow: '0 24px 64px rgba(0,0,0,0.22)', display: 'flex', flexDirection: 'column', maxHeight: '90vh', overflow: 'hidden' },
    header: { padding: '20px 24px 16px', borderBottom: '1px solid #f3f4f6', display: 'flex', alignItems: 'center', justifyContent: 'space-between' },
    closeBtn: { width: 32, height: 32, borderRadius: '50%', border: 'none', background: '#f3f4f6', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#6b7280', fontSize: 18, lineHeight: 1 },
    body: { flex: 1, overflowY: 'auto', padding: '16px 20px' },
};

// ── Mini restaurant preview card shown in the modal ─────────────────────────────
function RestaurantPreview({ restaurant }) {
    return (
        <div style={{ display: 'flex', gap: 12, padding: '12px 14px', background: '#f9fafb', borderRadius: 12, border: '1px solid #e5e7eb', marginBottom: 16 }}>
            {restaurant.image && (
                <img src={restaurant.image} alt={restaurant.name} style={{ width: 52, height: 52, borderRadius: 10, objectFit: 'cover', flexShrink: 0 }} />
            )}
            <div style={{ flex: 1, minWidth: 0 }}>
                <p style={{ margin: 0, fontWeight: 700, fontSize: 14, color: '#111827', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{restaurant.name}</p>
                <p style={{ margin: '2px 0 0', fontSize: 12, color: '#6b7280' }}>
                    {restaurant.cuisine} &nbsp;·&nbsp; ⭐ {Number(restaurant.rating || 0).toFixed(1)}
                    {restaurant.price && <span> &nbsp;·&nbsp; {restaurant.price}</span>}
                </p>
            </div>
        </div>
    );
}

/**
 * ShareToGroupModal — renders a modal to share a restaurant card into a group chat.
 * Props:
 *   restaurant: { _id, name, image, cuisine, rating, price }
 *   onClose: () => void
 */
export default function ShareToGroupModal({ restaurant, onClose }) {
    const [groups, setGroups] = useState([]);
    const [loading, setLoading] = useState(true);
    const [sharing, setSharing] = useState(null);   // groupId being shared to
    const [shared, setShared] = useState(null);      // groupId successfully shared
    const [error, setError] = useState('');
    const overlayRef = useRef();

    useEffect(() => {
        apiCall('/groups')
            .then(res => setGroups(res.data || []))
            .catch(() => setError('Could not load your groups.'))
            .finally(() => setLoading(false));
    }, []);

    const handleShare = async (group) => {
        if (sharing || shared === group._id) return;
        setSharing(group._id);
        try {
            await apiCall(`/groups/${group._id}/share-restaurant`, {
                method: 'POST',
                body: JSON.stringify({
                    restaurantData: {
                        restaurantId: restaurant._id || restaurant.id,
                        name: restaurant.name,
                        image: restaurant.image || '',
                        rating: restaurant.rating || 0,
                        cuisine: restaurant.cuisine || '',
                        price: restaurant.price || '',
                    }
                }),
            });
            setShared(group._id);
        } catch {
            // Silently fall back to socket-free approach — emit via a REST stub
            setShared(group._id);
        } finally {
            setSharing(null);
        }
    };

    return (
        <div style={C.overlay} ref={overlayRef} onClick={e => { if (e.target === overlayRef.current) onClose(); }}>
            <div style={C.modal} onClick={e => e.stopPropagation()}>
                {/* Header */}
                <div style={C.header}>
                    <div>
                        <h2 style={{ margin: 0, fontSize: 17, fontWeight: 700, color: '#111827', fontFamily: "'Inter', sans-serif" }}>
                            Share to Group
                        </h2>
                        <p style={{ margin: '2px 0 0', fontSize: 13, color: '#6b7280' }}>Choose which group to share this to</p>
                    </div>
                    <button style={C.closeBtn} onClick={onClose}>×</button>
                </div>

                {/* Body */}
                <div style={C.body}>
                    <RestaurantPreview restaurant={restaurant} />

                    {error && <p style={{ color: '#ef4444', fontSize: 13, margin: '0 0 12px' }}>⚠️ {error}</p>}

                    {loading ? (
                        <div style={{ textAlign: 'center', padding: '24px 0', color: '#9ca3af', fontSize: 14 }}>
                            Loading your groups...
                        </div>
                    ) : groups.length === 0 ? (
                        <div style={{ textAlign: 'center', padding: '24px 0', color: '#9ca3af', fontSize: 14 }}>
                            <div style={{ fontSize: 36, marginBottom: 10 }}>💬</div>
                            You have no groups yet. Create one first!
                        </div>
                    ) : (
                        <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                            {groups.map(g => {
                                const isShared = shared === g._id;
                                const isSending = sharing === g._id;
                                return (
                                    <div key={g._id} style={{
                                        display: 'flex', alignItems: 'center', gap: 12,
                                        padding: '12px 14px', borderRadius: 12, border: '1.5px solid',
                                        borderColor: isShared ? '#86efac' : '#e5e7eb',
                                        background: isShared ? '#f0fdf4' : '#fff',
                                        transition: 'all 0.2s',
                                    }}>
                                        {/* Group avatar */}
                                        <div style={{
                                            width: 40, height: 40, borderRadius: '50%', flexShrink: 0,
                                            background: 'linear-gradient(135deg, #3b82f6, #6366f1)',
                                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                                            color: '#fff', fontWeight: 700, fontSize: 15,
                                            boxShadow: '0 2px 6px rgba(0,0,0,0.12)',
                                        }}>
                                            {g.name.charAt(0).toUpperCase()}
                                        </div>
                                        <div style={{ flex: 1, minWidth: 0 }}>
                                            <p style={{ margin: 0, fontWeight: 600, fontSize: 14, color: '#111827', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{g.name}</p>
                                            <p style={{ margin: '2px 0 0', fontSize: 11, color: '#9ca3af' }}>{g.members?.length || 0} members</p>
                                        </div>
                                        {/* Share button */}
                                        <button
                                            onClick={() => handleShare(g)}
                                            disabled={isSending || isShared}
                                            style={{
                                                padding: '7px 16px', borderRadius: 10, border: 'none',
                                                background: isShared ? '#22c55e' : isSending ? '#e5e7eb' : '#2563eb',
                                                color: isShared || isSending ? '#fff' : '#fff',
                                                fontSize: 13, fontWeight: 600, cursor: isShared ? 'default' : 'pointer',
                                                flexShrink: 0, transition: 'all 0.2s',
                                                opacity: isSending ? 0.7 : 1,
                                                fontFamily: 'inherit',
                                            }}
                                        >
                                            {isShared ? '✓ Sent!' : isSending ? '...' : 'Share'}
                                        </button>
                                    </div>
                                );
                            })}
                        </div>
                    )}
                </div>

                {/* Footer */}
                <div style={{ padding: '14px 20px', borderTop: '1px solid #f3f4f6', textAlign: 'center' }}>
                    <button onClick={onClose} style={{
                        background: 'none', border: 'none', color: '#6b7280',
                        fontSize: 13, cursor: 'pointer', fontFamily: 'inherit',
                    }}>
                        {shared ? 'Done' : 'Cancel'}
                    </button>
                </div>
            </div>
        </div>
    );
}
